          "hypotheses": {
            "continuous": {
              "pass": true,
              "note": "the corner is continuous, just not smooth"
            },
            "differentiable": {
              "pass": false,
              "note": "left and right derivatives disagree at $x = 0$"
            },
            "monotonic": {
              "pass": false,
              "note": "decreases on $[-1, 0]$, increases on $[0, 1]$"
            },
            "bounded": {
              "pass": true,
              "note": "$0 \\le f(x) \\le 1$ on $[-1, 1]$"
            }
          }
